#include <stdio.h>
#include <math.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long sum = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            sum += x;
        }
        long long k = (long long)((sqrt(8.0 * sum + 1) - 1) / 2);
        // adjust in case of floating error
        while ((k + 1) * (k + 2) / 2 <= sum) ++k;
        while (k * (k + 1) / 2 > sum) --k;
        printf("%lld\n", k);
    }
    return 0;
}

