#!/usr/bin/env python3
import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        s = 0
        for _ in range(N):
            s += int(next(it))
        k = int((math.isqrt(8 * s + 1) - 1) // 2)  # using integer sqrt for safety
        # adjust if needed
        while (k + 1) * (k + 2) // 2 <= s:
            k += 1
        while k * (k + 1) // 2 > s:
            k -= 1
        out.append(str(k))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

